import type { TrendDirection } from '../types/trend-direction.js';

/**
 * Defines automatic behavior of trend direction if it is not configured
 *
 * @param directionProp -
 * @param valueProp -
 */
export function defineTrendDirection(
  directionProp?: TrendDirection,
  valueProp?: number,
) {
  let direction = directionProp;

  if (!direction) {
    direction = 'neutral';

    if (valueProp !== undefined) {
      if (valueProp > 0) {
        direction = 'upward';
      } else if (valueProp < 0) {
        direction = 'downward';
      }
    }
  }

  return direction;
}
